"""
MKT Original Language Commentary — 2 Kings chapters 16–17 (fill)
Run: python3 scripts/zc-original-2kings-16-17-fill.py

Fills verse-level gaps left by the prior 15-17 script.

Key decisions:
- Ch16: ʿābar bāʾēš formula (v3 — already present); treaty language of v7
  (Ahaz calls himself Tiglath-Pileser's ʾeḇed wᵉḇin = servant and son);
  Damascus altar — the only priestly innovation by royal command in the DH
- Ch17: The Deuteronomistic History's fullest theological retrospective;
  ḥuqqôt haggôyim as the core indictment; three-stage warning formula
  (prophets → rejection → exile); the syncretism formula of vv33/41
  (already present) as the theological climax; gālāh root for exile
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge without overwriting existing entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2 = {
  "16": {
    "1": "<p>Ahaz son of Jotham begins his reign in the seventeenth year of Pekah. The synchronism places him during the height of the Syro-Ephraimite crisis that dominates vv5-9. Ahaz reigns sixteen years — a relatively short tenure for a Judean king, which the narrative implicitly connects to his faithlessness. His reign is the critical hinge point for the Isaiah narratives (Isa 7-8) and the book of Micah.</p>",
    "2": "<p><em>ben ʿeśrîm šānāh ʾāḥāz bᵉmamlᵉḵô</em> — Ahaz was twenty years old when he began to reign. The regnal formula shifts immediately to the negative verdict: <em>wᵉlōʾ ʿāśāh hayyāšār bᵉʿênê YHWH ʾĕlōhāyw kᵉdāwid ʾāḇîw</em> — he did not do right in YHWH's eyes like David his father. The Davidic comparison, the standard benchmark for Judean kings, is withheld here — one of only a few Judean kings who fail even partial comparison. The contrast with Jotham (15:34) is stark.</p>",
    "4": "<p><em>wayzabbēaḥ wayzaqqēṭ babbāmôt ûʿal haggᵉḇāʿôt wᵉtaḥat kol-ʿēṣ raʿănān</em> — he sacrificed and burned incense on the high places (<em>bāmôt</em>), on the hills, and under every green tree. The phrase <em>taḥat kol-ʿēṣ raʿănān</em> (under every lush/green tree) is formulaic Deuteronomistic language for pagan cultic groves (Deut 12:2; 2 Kgs 17:10; Jer 2:20; Hos 4:13). The three-location formula — high places, hills, green trees — describes a dispersed cultic system outside the Jerusalem temple that the DH consistently condemns as syncretistic.</p>",
    "5": "<p>The Syro-Ephraimite war: <em>ʾāz yaʿăleh Rᵉṣîn melek ʾărām ûPeqaḥ ben-Rᵉmalyāhû melek yiśrāʾēl Yᵉrûšālaim lammilḥāmāh</em> — then Rezin king of Aram and Pekah son of Remaliah came up against Jerusalem in war. The campaign is contemporaneous with Isaiah's Immanuel oracle (Isa 7:1-17). <em>wayyāṣûrû ʿal ʾāḥāz wᵉlōʾ yāḵᵉlû lehillāḥēm</em> — they besieged Ahaz but could not fight/prevail. The siege fails, setting the stage for Ahaz's appeal to Assyria rather than faith in YHWH (cf. Isa 7:4-9).</p>",
    "6": "<p>A parenthetical military note: Rezin king of Aram recovered Elath for Aram (<em>hēšîḇ ʾet-ʾĒlat lăʾărām</em>) and drove out the Judeans. The port of Elath on the Red Sea had been a significant Judean asset (cf. 14:22); its loss to Aram marks the contraction of Judean territory under Ahaz. <em>waʾĂdōmîm bāʾû ʾĒlat wayyēšᵉḇû šām ʿad hayyôm hazzeh</em> — the Edomites came to Elath and dwelt there to this day.</p>",
    "7": "<p>Ahaz's letter to Tiglath-Pileser king of Assyria: <em>ʿaḇdᵉḵā ûḇinᵉḵā ʾānî</em> — &ldquo;I am your servant and your son.&rdquo; This formula — <em>ʿeḇed</em> (servant) + <em>bēn</em> (son) — is the standard language of vassal submission in Mesopotamian diplomatic correspondence. Calling himself &ldquo;son&rdquo; to the Assyrian king is an extraordinary claim of subordination that inverts the normal covenant language in which YHWH is Israel's father and king. <em>ʿălēh wᵉhôšîʿēnî miyyad melek ʾărām ûmiyyad melek yiśrāʾēl haqqāmîm ʿālay</em> — &ldquo;Come up and save me from the hand of the king of Aram and the king of Israel who rise against me.&rdquo; Ahaz looks to Assyria rather than YHWH for salvation (<em>hôšîʿēnî</em>).</p>",
    "8": "<p><em>wayyiqqaḥ ʾāḥāz ʾet-hakkesep wᵉʾet-hazzāhāḇ hannimṣāʾ bêt YHWH ûbᵉʾôṣᵉrôt bêt hamméleḵ wayyišlaḥ lamélek ʾAššûr šōḥad</em> — Ahaz took the silver and gold found in the house of YHWH and in the palace treasuries and sent it to the king of Assyria as a bribe (<em>šōḥad</em>). The term <em>šōḥad</em> (bribe, gift to obtain favor) is ethically loaded — it is elsewhere condemned in legal contexts (Deut 16:19; Exod 23:8). Taking temple treasure to pay a foreign king is a clear inversion of the proper order of tribute.</p>",
    "9": "<p>Tiglath-Pileser responds: <em>wayyiqqaḥ melek ʾAššûr ʾet-Dammeśeq wayyiglēhā</em> — the Assyrian king captured Damascus and exiled its population. <em>wayyiglēhā</em> is the qal of <em>gālāh</em> (to go into exile, to be deported) — the same root used in ch17 for Israel's exile. Damascus's fate prefigures what will happen to Samaria in ch17. <em>wᵉʾet-Rᵉṣîn hēmît</em> — and he killed Rezin. The Syro-Ephraimite threat is eliminated through Assyrian power that Ahaz purchased at the cost of temple treasure.</p>",
    "10": "<p>Ahaz travels to Damascus to meet Tiglath-Pileser — an act of political homage. There he sees (<em>wayyarᵉ ʾāḥāz ʾet-hammizbēaḥ ʾăšer bᵉDammeśeq</em>) the altar that was in Damascus. He sends to Uriah the priest the architectural specifications: <em>dᵉmût hammizbēaḥ ûtabnîtô lᵉḵol-maʿăśēhû</em> — the likeness (<em>dᵉmût</em>) of the altar and its pattern (<em>tabnît</em>) for all its workmanship. The use of <em>tabnît</em> (pattern, blueprint) recalls the tabernacle's heavenly blueprint (Exod 25:9) — here applied to a pagan altar model, a pointed irony.</p>",
    "11": "<p>Uriah the priest builds the altar: <em>wayyiḇen ʾUriyyāh hakōhēn ʾet-hammizbēaḥ kᵉḵōl ʾăšer šālaḥ hammélek ʾāḥāz mēDammeśeq</em> — according to all that King Ahaz sent from Damascus. Uriah is complicit — he carries out the king's instruction without prophetic objection recorded. The priest who enables royal apostasy is a recurring DH type. The speed of construction — completed before Ahaz returns — shows institutional compliance with royal innovation.</p>",
    "12": "<p>When the king returns from Damascus, he approaches (<em>wayyiqrab hammélek ʾel hammizbēaḥ wayyaʿal ʿālāyw</em>) the new altar and makes offerings on it. <em>wayyaʿal</em> — the technical term for ascending the altar (cf. Exod 20:26, which prohibits steps to the altar, though this is the Damascus model). The king himself performs the sacrificial acts, usurping a priestly function. The sequence of offerings — burnt, grain, libation, peace — mirrors the full sacrificial cycle.</p>",
    "13": "<p><em>wayyaqqēṭ ʾet-ʿōlātô wᵉʾet-minḥātô wayyisōḵ ʾet-niskô wayyizrōq ʾet-dam haššᵉlāmîm ʾăšer-lô ʿal hammizbēaḥ</em> — he offered his burnt offering and grain offering, poured his drink offering and dashed the blood of his peace offerings on the altar. The term <em>wayyaqqēṭ</em> (hiphil of <em>qāṭar</em>, to cause smoke to rise as incense/offering) is different from <em>ʿōlāh</em> (whole burnt offering); here used for offering incense. The complete sacrificial sequence is performed on the foreign-modeled altar.</p>",
    "14": "<p>Ahaz orders the original bronze altar moved: <em>wᵉʾet-hammizbāḥ hannᵉḥōšet ʾăšer lipnê YHWH wayyaqrēḇ mēʾet pᵉnê habbayt</em> — the bronze altar that was before YHWH he removed from before the house. The bronze altar — probably the Solomonic altar (1 Kgs 8:64) — is displaced to the north, out of the primary sacrificial position. Ahaz repurposes it: <em>wᵉhāyāh lî lᵉḇaqqēr</em> — it shall be for me to inquire by (<em>bāqar</em>, to investigate/determine). The original altar becomes an oracular instrument while the Damascus-pattern altar becomes the primary sacrificial site.</p>",
    "15": "<p>Ahaz's orders to Uriah: <em>ʿal hammizbēaḥ haggādôl qṭr ʾet-ʿōlat habboqer wᵉʾet minḥat hāʿereḇ</em> — on the great altar burn the morning burnt offering and the evening grain offering. The liturgical schedule — morning burnt offering, evening grain offering, royal offering — was the Temple's daily rhythm. Ahaz transfers all official worship to the new altar. The original Solomonic altar is reserved for his personal divination (<em>yihyeh lî lᵉḇaqqēr</em>). This is a systematic liturgical replacement, not mere syncretism.</p>",
    "16": "<p><em>wayyaʿaś ʾUriyyāh hakōhēn kᵉḵōl ʾăšer ṣiwwāh hammélek ʾāḥāz</em> — Uriah the priest did according to all that King Ahaz commanded. The repetition of the priest's compliance underscores the institutional failure: the Jerusalem priesthood executed royal liturgical innovation without prophetic resistance. The comparison with Moses' priestly obedience to YHWH's commands in Exodus is implicit and damning — here a priest obeys a king rather than YHWH.</p>",
    "17": "<p>Further dismantling of the temple furnishings: Ahaz cuts the frames (<em>wayyᵉqaṣṣēṣ ʾāḥāz ʾet-hammisgᵉrôt</em>) of the bronze stands and removes the basins. He also removes the Bronze Sea from the bronze oxen supporting it and sets it on a stone pavement. The Bronze Sea and its twelve ox supports were among the signature Solomonic furnishings (1 Kgs 7:23-26); stripping them signals both theological deconstruction and political-economic urgency — tribute to Assyria requires precious metal.</p>",
    "18": "<p>The covered way (<em>mûsak haššabbāt</em>) built in the temple is removed, and the royal entrance (<em>ûmebôʾ hammélek haḥîṣônāh</em>) is turned toward the Assyrian king's requirements. The term <em>mûsak haššabbāt</em> (the Sabbath covering, or Sabbath portico) is unique to this verse; it may have been a structure built for special Sabbath royal participation in worship. Its removal &ldquo;on account of the king of Assyria&rdquo; suggests it was either too ostentatiously Israelite or was dismantled for its materials. The verse completes the picture: Ahaz has subordinated the entire temple apparatus to Assyrian vassalage.</p>",
    "19": "<p>The standard closing formula: <em>wᵉyeter diḇrê ʾāḥāz ʾăšer ʿāśāh hălōʾ hēm kᵉtûḇîm ʿal sēper diḇrê hayyāmîm lᵉmalkê yᵉhûdāh</em> — the rest of the acts of Ahaz, are they not written in the Book of Chronicles of the Kings of Judah? The formula signals the official court record as source material. Ahaz's full chronicle — including alliances, building projects, and presumably the full altar correspondence — was preserved in the annals now lost.</p>",
    "20": "<p><em>wayyiškaḇ ʾāḥāz ʿim ʾăḇōtāyw wayyiqqāḇēr ʿim ʾăḇōtāyw bᵉʿîr dāwid</em> — Ahaz slept with his fathers and was buried with his fathers in the city of David. The burial notation carries no special honor — he is buried in David's city but there is no note of burial in a specific tomb of kings (contrast Hezekiah's honored burial, 2 Chr 32:33). <em>wayyimloḵ ḥizqiyyāhû bᵉnô taḥtāyw</em> — his son Hezekiah reigned in his place. The contrast between Ahaz (most apostate Judean king to this point) and Hezekiah (one of the most faithful) is the sharpest royal reversal in Kings.</p>"
  },
  "17": {
    "1": "<p>Hoshea son of Elah begins his reign in the twelfth year of Ahaz of Judah — a Judean synchronism placing the last Israelite king within Ahaz's apostate reign. The synchronism forms an implicit theological link: the northern kingdom falls during the reign of Judah's most apostate king, not (as one might expect) during a righteous Judean reign. The irony is the DH's design.</p>",
    "2": "<p><em>wayyaʿaś hāraʿ bᵉʿênê YHWH raḵ lōʾ ḵᵉmalkê yiśrāʾēl ʾăšer hāyû lᵉpānāyw</em> — he did evil in YHWH's eyes, but not as the kings of Israel who were before him. The qualified negative formula — evil but not as bad as predecessors — is unusual for a northern king. Hoshea receives a mild relative compliment, yet his kingdom still falls. The point: accumulated covenant violation cannot be undone by a single king's relative improvement.</p>",
    "3": "<p><em>ʿālāyw ʿālāh Šalmaneʾeser melek ʾAššûr</em> — Shalmaneser king of Assyria came up against him (Hoshea). Hoshea becomes his vassal (<em>ʿeḇed</em>) and pays tribute (<em>wayyāšeb lô minḥāh</em>). The term <em>minḥāh</em> here means tribute (as in 2 Kgs 3:4; Ps 72:10) — not the cultic grain offering but the political gift of a subordinate to a superior. Hoshea's early submission to Assyria buys time.</p>",
    "4": "<p>Hoshea conspires (<em>wayyimṣāʾ melek ʾAššûr bᵉHôšēaʿ qešer</em>) — the Assyrian king found a conspiracy in Hoshea. He had sent envoys to <em>Sôʾ melek miṣrāyim</em> (So king of Egypt). <em>Sôʾ</em> is unidentified — perhaps Osorkon IV or Tefnakht — but Egypt is the alternative to Assyrian suzerainty. The withholding of tribute (<em>wᵉlōʾ-hēʿĕlāh minḥāh lamélek ʾAššûr kaššānāh bᵉšānāh</em>) is the formal act of rebellion. The Assyrian response is Hoshea's arrest and imprisonment (<em>wayyeʾsᵉrēhû ûyitᵉnēhû bêt kele</em>).</p>",
    "5": "<p><em>wayyaʿal melek ʾAššûr bᵉḵol-hāʾāreṣ wayyaʿal Šomrôn wayyāṣar ʿālehā šālôš šānîm</em> — the Assyrian king marched through the entire land and came up against Samaria, besieging it for three years. The three-year siege (723-721 BCE) is one of the few precisely timed military operations in Kings. The final capture is by Sargon II (who appears in the Assyrian annals claiming credit, though 2 Kgs 17:6 implies Shalmaneser V completed it), though the text does not name the Assyrian king who takes the city.</p>",
    "6": "<p><em>bišnat haттᵉšîʿît lᵉHôšēaʿ lāḵad melek ʾAššûr ʾet-Šomrôn wayyegel ʾet-yiśrāʾēl ʾAššûrāh</em> — in the ninth year of Hoshea the Assyrian king captured Samaria and deported Israel to Assyria. <em>wayyegel</em> is the hiphil of <em>gālāh</em> — caused to go into exile, deported. The destinations: Halah, on the Habor (a tributary of the Euphrates), the cities of the Medes. Halah and Gozan are attested in Assyrian records. This verse is the culmination of the entire Northern Kingdom narrative from 1 Kings 12 — the division, the Jeroboam sin, the prophets, the warnings — all compressed into this single deportation notice.</p>",
    "7": "<p>The great theological retrospective begins: <em>wayhî ḵî ḥāṭᵉʾû ḇᵉnê yiśrāʾēl laYHWH ʾĕlōhêhem</em> — it came to pass because the children of Israel sinned against YHWH their God. The DH author provides the longest theological explanation in Kings, anchoring the exile in a chain of covenant violation. The first charge: <em>hammāʿăleh ʾōtām mēʾereṣ miṣrāyim mTaḥat yad parʿōh melek miṣrāyim wayyîrᵉʾû ʾĕlōhîm ʾăḥērîm</em> — they feared other gods, the God who brought them from Egypt. The Exodus is the theological baseline; the violation is measured against YHWH's founding act of liberation.</p>",
    "8": "<p><em>wayyēlḵû bᵉḥuqqôt haggôyim</em> — they walked in the statutes of the nations (<em>ḥuqqôt</em>, the binding ordinances/customs of the surrounding peoples). The phrase <em>ḥuqqôt haggôyim</em> is the DH's core indictment of Israel: they adopted the behavioral codes of the Canaanites and the kings of Israel. <em>ḥuqqôt</em> (from <em>ḥāqaq</em>, to engrave/decree) denotes legislated or socially binding norms — not casual practices but systemic cultural adoption. The critique is not merely religious but civilizational: Israel stopped being distinctively Israel.</p>",
    "9": "<p><em>wayḥappᵉʾû ḇᵉnê yiśrāʾēl dᵉḇārîm ʾăšer lōʾ kēn ʿal YHWH ʾĕlōhêhem</em> — the children of Israel secretly did (<em>ḥippāʾ</em> piel: to veil, conceal, do covertly) things that were not right against YHWH their God. They built high places (<em>bāmôt</em>) in all their cities — from watchtower to fortified city. The comprehensiveness — every settlement, every size — emphasizes that the apostasy was systemic, not isolated.</p>",
    "10": "<p><em>wayyaṣṣiḇû lāhem maṣṣēḇôt wᵉʾăšērîm ʿal kol-giḇʿāh gᵉḇōhāh wᵉtaḥat kol-ʿēṣ raʿănān</em> — they set up standing stones (<em>maṣṣēḇôt</em>) and Asherah poles (<em>ʾăšērîm</em>) on every high hill and under every green tree. The <em>maṣṣēḇāh</em> (sacred standing stone) was originally a legitimate memorial (Gen 28:18) but became associated with Canaanite male deity representation. The <em>ʾăšērāh</em> was the symbol of the Canaanite mother-goddess, often a wooden pole or stylized tree. The geographic formula (high hill + green tree) matches v4 of ch16 — Judah and Israel share the same cultic landscape.</p>",
    "11": "<p><em>wayyᵉqaṭṭᵉrû šām bᵉḵol-bāmôt</em> — they burned incense on all the high places, as the nations whom YHWH had sent into exile (<em>gālāh</em>) before them. The comparison is precise: Israel is now doing what the nations did — who were themselves exiled. The irony is explicit: Israel worships the way of the people whose land they inherited, and will suffer the same fate (exile) those people suffered. <em>wayyarᵉšîʿû</em> — they acted wickedly, provoking (<em>kaʿas</em> hiphil) YHWH.</p>",
    "12": "<p><em>wayyaʿaḇdû haggillûlîm</em> — they served the idols (<em>gillûlîm</em>). The term <em>gillûlîm</em> is a deliberately contemptuous word for idols, related to the root for dung pellets (<em>gālal</em>). Used 48 times in Ezekiel, it is the prophetic literature's most derogatory idol vocabulary. The notice continues: <em>ʾăšer ʾāmar YHWH lāhem lōʾ taʿăśûn ʾet-haddāḇār hazzeh</em> — which YHWH had told them not to do. Every element of Israel's sin has an explicit divine prohibition it violated.</p>",
    "13": "<p>The prophetic warning phase: <em>wayyāʿad YHWH bᵉyiśrāʾēl ûḇîhûdāh bᵉyad kol-nᵉḇiʾô kol-ḥōzeh lēʾmōr šûḇû middarᵉḵêkem hārāʿîm</em> — YHWH testified (<em>ʿûd</em> hiphil: to solemnly warn, bear witness) against both Israel and Judah through every prophet and every seer: &ldquo;Turn from your evil ways.&rdquo; The paired terms <em>nāḇîʾ</em> (prophet) and <em>ḥōzeh</em> (seer/visionary) represent the full spectrum of prophetic roles. <em>šûḇû</em> (return, repent) is the classic prophetic call — the word that encapsulates the entire prophetic message.</p>",
    "14": "<p><em>wᵉlōʾ šāmēʿû wayyaqšû ʾet ʿorpām kᵉʿōrep ʾăḇōtām ʾăšer lōʾ hāmᵉʾînû baYHWH ʾĕlōhêhem</em> — they would not listen but stiffened their necks (<em>qāšāh ʿōrep</em> = hardened the neck, the idiom for obstinate disobedience) like the necks of their fathers who did not believe in YHWH. The &ldquo;stiff neck&rdquo; image originates with the golden calf rebellion (Exod 32:9; 33:3) and becomes the standard DH idiom for covenantal stubbornness. The phrase <em>lōʾ hāmᵉʾînû</em> (did not trust/believe, hiphil of <em>ʾāman</em>) adds the faith dimension — it was not merely behavioral but a failure of trust.</p>",
    "15": "<p><em>wayyimʾăsû ʾet-ḥuqqāyw wᵉʾet-bᵉrîtô ʾăšer kārat ʾet-ʾăḇōtām</em> — they rejected (<em>māʾas</em>, to despise/reject) his statutes and his covenant that he made with their fathers. The verb <em>māʾas</em> (to reject, treat as worthless) is strong — not neglect but active repudiation. The covenant is the Sinai covenant confirmed with the exodus generation. <em>wᵉʾet-ʿēdᵉwōtāyw ʾăšer hēʿîd bām</em> — and his testimonies (<em>ʿēdûtôt</em>, covenant stipulations/witnesses) that he solemnly warned them with. They followed the nations — <em>wayyēlᵉḵû ʾaḥărê hahheḇel wayyehbāllû</em> — followed emptiness (<em>heḇel</em>, vanity, breath — the same word as Ecclesiastes' <em>hăḇel hăḇālîm</em>) and became empty/vain.</p>",
    "16": "<p><em>wayyaʿaḇrû ʾet-kol-miṣwôt YHWH ʾĕlōhêhem wayyaʿăśû lāhem massēḵāh šᵉnê ʿăgālîm wayyaʿăśû ʾăšērāh wayyišteḥăwû lᵉḵol-ṣᵉḇāʾ haššāmāyim wayyaʿaḇdû ʾet-habbaʿal</em> — they forsook all the commandments of YHWH and made for themselves two molten calves (<em>massēḵāh šᵉnê ʿăgālîm</em>). The two golden calves are Jeroboam's foundational sin (1 Kgs 12:28). They also made Asherah, worshiped all the host of heaven (<em>ṣᵉḇāʾ haššāmāyim</em> — astral worship) and served Baal. The cumulative list — calves, Asherah, astral worship, Baal — represents the full syncretistic package.</p>",
    "17": "<p><em>wayyaʿăḇirû ʾet-bᵉnêhem wᵉʾet-bᵉnōtêhem bāʾēš wayyiqsᵉmû qᵉsāmîm wayyᵉnaḥēšû</em> — they caused their sons and daughters to pass through fire (<em>heʿăḇîr bāʾēš</em>, the Molech formula from ch16:3), practiced divination (<em>qāsam qᵉsāmîm</em>) and sought omens (<em>naḥaš</em>, to practice augury/divination from signs). Both divination practices are explicitly prohibited in Deut 18:10-11. <em>wayyimkᵉrû laʿăśôt hāraʿ bᵉʿênê YHWH lᵉhakʿîsô</em> — they sold themselves (<em>mākar</em>) to do evil in YHWH's eyes to provoke him. <em>mākar</em> (to sell) used reflexively means to give oneself wholly over — a total self-dedication to evil.</p>",
    "18": "<p><em>wayyitʾannap YHWH mᵉʾōd bᵉyiśrāʾēl wayyᵉsîrēm mēʿal pānāyw lōʾ nišʾar raq šēḇeṭ yᵉhûdāh lᵉḇaddô</em> — YHWH was very angry (<em>ʾānaph</em> hithpael: to be furiously angry) at Israel and removed them from before his face (<em>wayyᵉsîrēm mēʿal pānāyw</em>). The idiom of &ldquo;before the face&rdquo; recalls the priestly blessing (<em>yāʾēr YHWH pānāyw ʾēlêḵā</em>, Num 6:25) and the covenantal presence — to be removed from before YHWH's face is the loss of covenantal standing. Only the tribe of Judah remained.</p>",
    "19": "<p>The Judah parenthesis: <em>gam-yᵉhûdāh lōʾ šāmar ʾet-miṣwôt YHWH ʾĕlōhêhem wayyēlᵉḵû bᵉḥuqqôt yiśrāʾēl ʾăšer ʿāśû</em> — even Judah did not keep YHWH's commandments but walked in the statutes of Israel that they had made. The insertion is crucial: Judah's narrative is not fundamentally different from Israel's. The fall of Samaria is prologue to Jerusalem — the same DH logic will produce the same outcome in 2 Kgs 25. The rhetoric of ch17 is implicitly addressed to Judah reading this history.</p>",
    "20": "<p><em>wayyimʾas YHWH bᵉḵol-zeraʿ yiśrāʾēl wayyᵉʿannēm wayyitnēm bᵉyad šōsîm ʿad ʾăšer hišlîḵām mēʿal pānāyw</em> — YHWH rejected (<em>māʾas</em>) all the offspring of Israel and afflicted (<em>ʿinnāh</em> piel) them and gave them into the hand of plunderers until he cast them away from before his face. The verb <em>hišlîḵ</em> (to throw/cast away) is especially strong — it implies abandonment of something formerly precious. The same verb is used in Ps 51:13 for David's prayer: &ldquo;Do not cast me away from your presence&rdquo; (<em>ʾal-tašlîḵēnî mēl-pānêḵā</em>).</p>",
    "21": "<p><em>kî qāraʿ yiśrāʾēl mēʿal bêt dāwid wayyamlîḵû ʾet-Yarobʿām ben-Nᵉḇāṭ</em> — for he tore (<em>qāraʿ</em>) Israel from the house of David and they made Jeroboam son of Nebat king. The verb <em>qāraʿ</em> (to tear, as in tearing cloth) evokes the Ahijah prophecy (1 Kgs 11:30-31) and Saul's torn robe (1 Sam 15:27). <em>wayyaddaḥ Yarobʿām ʾet-yiśrāʾēl mēʾaḥărê YHWH</em> — Jeroboam drove Israel away (<em>nādaḥ</em> hiphil) from following YHWH and made them commit a great sin. <em>nādaḥ</em> (to push away, scatter, exile) used here is causative: Jeroboam actively expelled Israel from YHWH's orbit.</p>",
    "22": "<p><em>wayyēlᵉḵû ḇᵉnê yiśrāʾēl bᵉḵol-ḥaṭṭōʾt Yarobʿām ʾăšer ʿāśāh lōʾ sārû mimmennāh</em> — the children of Israel walked in all the sins of Jeroboam which he committed; they did not turn (<em>sûr</em>) from them. The phrase <em>lōʾ sārû</em> (they did not depart/turn) echoes the DH's repeated prophetic call and the standard regnal formula (&ldquo;did not turn from the sin of Jeroboam&rdquo;) used for virtually every northern king. The pattern hardened into identity. <em>ʿad ʾăšer hēsîr YHWH ʾet-yiśrāʾēl mēʿal pānāyw</em> — until YHWH removed Israel from before his face — the same formula as v18, now applied to the whole history.</p>",
    "23": "<p><em>ʿad ʾăšer hēsîr YHWH ʾet-yiśrāʾēl mēʿal pānāyw kaʾăšer dibber bᵉyad kol-ʿăḇādāyw hannᵉḇiʾîm</em> — just as YHWH had spoken through all his servants the prophets. The exile is not a catastrophe but a fulfillment of prophetic announcement — the word of YHWH through the prophets has been vindicated. <em>wayyigl yiśrāʾēl mēʿal ʾadmātô ʾAššûrāh ʿad hayyôm hazzeh</em> — Israel was exiled from its land to Assyria to this day. The formula <em>ʿad hayyôm hazzeh</em> (to this day) is a marker of the DH's compositional horizon — the author is writing after the exile, looking back at its continuation.</p>",
    "24": "<p>The Assyrian resettlement: <em>wayyāḇēʾ melek ʾAššûr miBāḇel ûmiKûtāh ûmēʿAwa ûmēḤamāt ûSᵉpharwāyim</em> — the king of Assyria brought people from Babylon, Cuthah, Avva, Hamath, and Sepharvaim and settled them in Samaria's cities. This is Sargon II's documented resettlement policy: deporting conquered populations and mixing them with new settlers to prevent nationalist cohesion. The cities named span Babylonia (Babylon, Cuthah), Syria (Hamath), and unknown locations (Avva, Sepharvaim). <em>wayyirᵉšû ʾet-Šomrôn wayyēšᵉḇû bᵉʿārāyw</em> — they took possession of Samaria and settled in its cities.</p>",
    "25": "<p>The lion problem: <em>ûḇitḥillat šiḇtām šām lōʾ yārᵉʾû ʾet YHWH</em> — at the beginning of their settlement there, they did not fear (<em>yārēʾ</em>) YHWH. <em>wayyišlaḥ YHWH bāhem ʾet-hāʾărāyôt wayyihyû hōrᵉgîm bāhem</em> — YHWH sent lions among them which killed some of them. The lion-killing is the standard DH sign of divine displeasure with those who occupy land improperly (cf. 1 Kgs 13:24; 20:36). It is interpreted as the land's response to those who do not know the land's God — a territorial theology: every land has its deity whose worship is required.</p>",
    "26": "<p>A report reaches the Assyrian king: <em>haggôyim ʾăšer higlîtā wayyōšeḇ bᵉʿārê Šomrôn lōʾ yādᵉʿû ʾet mišpaṭ ʾĕlōhê hāʾāreṣ</em> — the nations you deported and settled in Samaria's cities do not know the custom (<em>mišpaṭ</em>) of the god of the land. <em>mišpaṭ</em> here means the required religious observance — how the territorial deity is properly worshiped. The logic is thoroughly polytheistic from the settlers' perspective: YHWH is the local deity of Canaan requiring local cult practices. The Assyrian king's response — send back an Israelite priest — treats YHWH as a regional patron deity.</p>",
    "27": "<p>The Assyrian king commands: <em>hōlîḵû šāmmāh ʾeḥad mēhakkōhănîm ʾăšer higlîtem miššām</em> — send back one of the priests you deported from there. <em>wᵉyēlᵉḵû wᵉyēšᵉḇû šām wᵉyōrēm ʾet-mišpaṭ ʾĕlōhê hāʾāreṣ</em> — let him go and live there and teach them the custom of the god of the land. The priest is sent not for theological reasons but administrative ones — to stop the lion deaths. The result is a kind of institutional syncretism: Yahwistic priesthood teaching foreign settlers how to perform token YHWH observance. The priest settles in Bethel — the northern cult site of Jeroboam's calves.</p>",
    "28": "<p><em>wayyābōʾ ʾeḥad mēhakkōhănîm ʾăšer higlû miŠomrôn wayyēšeḇ bᵉBêt-ʾĒl wayhî mōreh ʾōtām ʾēḵ yîrᵉʾû ʾet-YHWH</em> — one of the priests who had been exiled from Samaria came and settled in Bethel and taught them how to fear (<em>yārēʾ</em>) YHWH. The priestly settlement in Bethel — the site of the golden calf — is a historical-theological irony the narrator does not miss. The priest who teaches <em>how to fear YHWH</em> in Bethel is teaching in the same place where false YHWH-worship was institutionalized by Jeroboam. Authentic YHWH-worship cannot take root in the temple of the calf.</p>",
    "29": "<p><em>wayhî gôy gôy ʿōśeh ʾet ʾĕlōhāyw</em> — but each nation made its own gods and placed them in the shrines of the high places that the Samaritans had made. The catalog follows: Babylonians made Succoth-benoth, men of Cuth made Nergal, men of Hamath made Ashima. Each ethnic group imports its own deity into the religious landscape. <em>Sukkôt-Bᵉnôt</em> is possibly Zarpanitu, consort of Marduk. Nergal is the Babylonian god of the underworld and war, patron of Cuthah. Ashima is unidentified but appears in Amos 8:14 in a polemical context.</p>",
    "30": "<p>The catalog continues: the Avvites made Nibhaz and Tartak; the Sepharvites burned their children in fire to Adrammelech and Anammelech. Adrammelech (<em>ʾAdrammeleḵ</em>) and Anammelech are associated with the Sepharvaim cult — their exact identity is uncertain (perhaps Mesopotamian deities or compound names). The child sacrifice (<em>haśrîpû bāʾēš</em>) language echoes the <em>heʿăḇîr bāʾēš</em> formula from 16:3 and 17:17 — Sepharvaim settlers practice the same Molech-type rite that was condemned in Judah and Israel.</p>",
    "31": "<p><em>wayhî Šomrônî yirᵉʾîm ʾet YHWH</em> — the Samaritans feared YHWH (they do worship YHWH, after a fashion). But they also served their own gods — each ethnic group retaining its own deities. <em>kᵉmišpaṭ haggôyim ʾăšer-higlû ʾōtām mišāmm</em> — according to the custom of the nations from which they were exiled. The Samaritan religious practice is thus doubly determined: by the imported YHWH-worship taught by the Bethel priest, and by the native cults of each ethnic community. The result is the syncretism the DH considers worse than pure paganism — a corruption of YHWH-worship rather than straightforward idolatry.</p>",
    "32": "<p><em>wayhî yᵉrēʾîm ʾet YHWH wayyaʿăśû lāhem miqṣôtām kōhănê bāmôt</em> — they feared YHWH but appointed from their midst priests of the high places (<em>bāmôt</em>) who officiated for them in the shrines. The appointment of non-Levitical, non-priestly personnel for the YHWH cult at high places is the recurring problem of the northern shrines (cf. 1 Kgs 13:33). The structure — fear of YHWH + non-authorized priesthood + high place worship — mirrors the Jeroboam pattern applied now to ethnic outsiders.</p>",
    "34": "<p><em>ʿad hayyôm hazzeh hēm ʿōśîm kammišpāṭîm hāriʾšōnîm</em> — to this day they follow the former customs. <em>ʾênām yᵉrēʾîm ʾet YHWH</em> — they do not fear YHWH. This is the narrator's definitive verdict: despite the Bethel priest's instruction, the settler populations do not truly fear YHWH. The double standard is the point: apparent YHWH-worship combined with other-god service is worse than simple paganism, because it corrupts YHWH-worship itself with syncretistic elements. The formula <em>kammišpāṭîm hāriʾšōnîm</em> (according to the former customs) traces the persistence of pre-Yahwistic practice.</p>",
    "35": "<p>The covenantal counter-statement: <em>wᵉYHWH kārat ʾittām bᵉrît wayyᵉṣaw ʾōtām lēʾmōr lōʾ tîrᵉʾû ʾĕlōhîm ʾăḥērîm</em> — YHWH had cut a covenant with them and commanded them: &ldquo;You shall not fear other gods.&rdquo; This is YHWH's covenant with Israel at Sinai (Exod 20:3; Deut 5:7). The use of <em>kārat bᵉrît</em> (to cut a covenant, the standard covenant-making idiom) in this context of settler syncretism is pointed — the covenant's demand was made to these very people (as heirs of the exile) even if they didn't know it.</p>",
    "36": "<p><em>kî ʾim ʾet-YHWH ʾăšer heʿĕlāh ʾetḵem mēʾereṣ miṣrāyim bᵉḵōaḥ gādôl ûḇizrôaʿ nᵉṭûyāh ʾōtô tîrᵉʾû wᵉlô tišteḥăwû wᵉlô tizbaḥû</em> — but YHWH who brought you up from the land of Egypt with great power and an outstretched arm (<em>ûḇizrôaʿ nᵉṭûyāh</em>) — him you shall fear, him you shall worship, him you shall sacrifice to. The <em>zᵉrôaʿ nᵉṭûyāh</em> (outstretched arm) is the standard Exodus-liberation formula (Exod 6:6; Deut 4:34; 5:15). The irony is that these instructions are being quoted for settlers who were never in Egypt — yet the covenant's claims are presented as universal for those who inhabit the covenant land.</p>",
    "37": "<p><em>wᵉʾet-haḥuqqîm wᵉʾet-hammišpāṭîm wᵉʾet-hattôrāh wᵉʾet-hammiṣwāh ʾăšer kāṯaḇ lāḵem tišmᵉrû laʿăśôt kol-hayyāmîm</em> — the statutes, ordinances, Torah, and commandments that he wrote for you — observe them, doing them all the days. The fourfold legal vocabulary — <em>ḥuqqîm</em> (statutes), <em>mišpāṭîm</em> (ordinances/judgments), <em>tôrāh</em> (instruction/law), <em>miṣwāh</em> (commandment) — represents the full spectrum of covenant obligations. The phrase <em>ʾăšer kāṯaḇ lāḵem</em> (which he wrote for you) indicates the written Torah as the covenant medium.</p>",
    "38": "<p><em>wᵉhabbᵉrît ʾăšer kāratî ʾittᵉḵem lōʾ tišḵāḥû</em> — the covenant that I cut with you, you shall not forget. <em>šāḵaḥ</em> (to forget) is the DH's key verb for covenantal amnesia — it was forgetting the covenant that led to idol-worship (Deut 6:12; 8:11, 14). The prohibition of forgetting is the positive counterpart to the Shema's positive command to remember (Deut 6:4-9).</p>",
    "39": "<p><em>kî ʾim ʾet YHWH ʾĕlōhêḵem tîrᵉʾû</em> — but YHWH your God you shall fear. <em>wᵉhûʾ yaṣṣîl ʾetḵem miyyad kol-ʾōyᵉḇêḵem</em> — and he will deliver you from the hand of all your enemies. The conditional promise reinforces the covenant structure: fear YHWH → receive deliverance. The structure mirrors the covenant curses/blessings of Deuteronomy. The promise of divine deliverance is the motivational ground for YHWH-exclusive worship — not theological speculation but pragmatic security.</p>",
    "40": "<p><em>wᵉlōʾ šāmēʿû kî ʾim kᵉmišpāṭām hāriʾšôn hēm ʿōśîm</em> — but they did not listen; they continued their former custom. <em>kᵉmišpāṭām hāriʾšôn</em> (their former custom) is the phrase from v34 — the settled habits of multiple ethnic syncretisms. The word <em>hēm ʿōśîm</em> (they keep doing) uses the participle of ongoing action — this is not a past sin but a present and continuing state of affairs. The DH narrator has collapsed the distinction between historical Israel and the Samaritans of his own day.</p>"
  }
}

if __name__ == "__main__":
    comm = load_comm("mkt-original", "2kings")
    merge_comm(comm, KINGS2)
    save_comm("mkt-original", "2kings", comm)
    print("Done. Verifying ch16-17...")
    result = json.loads((ROOT / "data/commentary/mkt-original/2kings.json").read_text())
    import json as _j
    with open(ROOT / "data/interlinear/2kings.json") as f:
        inter = _j.load(f)
    for ch in ["16", "17"]:
        il_vv = set(inter[ch].keys())
        out_vv = set(result.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f"  ch{ch}: STILL MISSING {sorted(missing, key=int)}")
        else:
            print(f"  ch{ch}: complete ({len(out_vv)} verses)")
